import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Review from './Review';
import ReviewForm from './ReviewForm';

function BookDetails({ bookId, onBack, api_url }) {
  const [book, setBook] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchBookDetails();
  }, [bookId]);

  const fetchBookDetails = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await axios.get(`${api_url}/books/${bookId}`);
      setBook(response.data);
    } catch (err) {
      setError('Could not fetch book details.');
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleReviewAdded = (newReview) => {
    setBook(prevBook => ({
      ...prevBook,
      reviews: [...prevBook.reviews, newReview],
    }));
  };

  const handleReviewDeleted = (reviewId) => {
    setBook(prevBook => ({
      ...prevBook,
      reviews: prevBook.reviews.filter(review => review.id !== reviewId),
    }));
  };

  const handleReviewEdited = (updatedReview) => {
    setBook(prevBook => ({
      ...prevBook,
      reviews: prevBook.reviews.map(review =>
        review.id === updatedReview.id ? updatedReview : review
      ),
    }));
  };

  if (isLoading) return <div className="text-center mt-20 text-xl text-gray-500">Loading...</div>;
  if (error) return <div className="text-center mt-20 text-xl text-red-500">{error}</div>;
  if (!book) return null;

  return (
    <div className="container mx-auto p-4">
      <button
        onClick={onBack}
        className="mb-6 px-4 py-2 bg-gray-200 text-gray-800 rounded-full hover:bg-gray-300 transition-colors duration-200 font-semibold"
      >
        &larr; Back to all books
      </button>

      <div className="bg-white rounded-xl shadow-lg p-8">
        <h1 className="text-4xl font-bold text-gray-900">{book.title}</h1>
        <p className="text-xl text-gray-600 mt-2 font-medium">by {book.author}</p>
        <div className="flex items-center mt-4">
          <span className="text-yellow-500 text-2xl">⭐</span>
          <span className="ml-2 text-2xl font-semibold text-gray-800">{book.rating}</span>
        </div>
      </div>

      <div className="mt-8">
        <h2 className="text-3xl font-bold text-gray-900 mb-4">Reviews</h2>
        {book.reviews.length > 0 ? (
          <div className="space-y-6">
            {book.reviews.map(review => (
              <Review
                key={review.id}
                review={review}
                bookId={book.id}
                api_url={api_url}
                onReviewDeleted={handleReviewDeleted}
                onReviewEdited={handleReviewEdited}
              />
            ))}
          </div>
        ) : (
          <p className="text-gray-500 italic">No reviews yet. Be the first to add one!</p>
        )}
      </div>

      <ReviewForm bookId={book.id} onReviewAdded={handleReviewAdded} api_url={api_url} />
    </div>
  );
}

export default BookDetails;
